document.addEventListener('DOMContentLoaded', () => {
  const search = document.getElementById('proof-search');
  const filters = document.getElementById('proof-topic-filters');
  const list = document.getElementById('proof-list');
  const count = document.getElementById('proof-count');
  const selectAll = document.getElementById('proof-select-all');
  const clear = document.getElementById('proof-clear');

  const topics = [...new Set(PROOFS.map(p => p.topic))];
  topics.forEach(topic => {
    const id = 'topic-' + slug(topic);
    const label = document.createElement('label');
    label.className = 'topic-chip';
    label.innerHTML = `<input type="checkbox" id="${id}" value="${escapeAttr(topic)}" checked> ${escapeHtml(topic)}`;
    filters.appendChild(label);
  });

  filters.addEventListener('change', render);
  search.addEventListener('input', render);
  selectAll.addEventListener('click', () => { filters.querySelectorAll('input').forEach(cb => cb.checked = true); render(); });
  clear.addEventListener('click', () => { filters.querySelectorAll('input').forEach(cb => cb.checked = false); render(); });

  render();

  function selectedTopics() {
    return new Set([...filters.querySelectorAll('input:checked')].map(cb => cb.value));
  }

  function render() {
    const selected = selectedTopics();
    const q = normalize(search.value);
    const filtered = PROOFS.filter(p => selected.has(p.topic)).filter(p => {
      if (!q) return true;
      return normalize([p.kind, p.num, p.title, p.topic, p.statement, p.proof, p.source].join(' ')).includes(q);
    });

    count.textContent = `Zobrazené: ${filtered.length} / ${PROOFS.length} výsledkov.`;
    list.innerHTML = '';
    filtered.forEach(p => list.appendChild(proofCard(p)));
  }

  function proofCard(p) {
    const article = document.createElement('article');
    article.className = 'proof-card card';
    article.dataset.topic = p.topic;
    article.innerHTML = `
      <div class="proof-meta">
        <span class="badge">${escapeHtml(p.kind)} ${escapeHtml(p.num)}</span>
        <span class="badge secondary">${escapeHtml(p.topic)}</span>
        <span class="source">Zdroj: ${escapeHtml(p.source)}</span>
      </div>
      <h2>${formatMathText(p.title)}</h2>
      <div class="proof-section">
        <h3>Tvrdenie</h3>
        <p>${formatMathText(p.statement)}</p>
      </div>
      <details class="proof-details">
        <summary>Dôkazová myšlienka / dôkaz</summary>
        <p>${formatMathText(p.proof)}</p>
      </details>`;
    return article;
  }

  function normalize(s) {
    return String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  }
  function slug(s) { return normalize(s).replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''); }
  function escapeHtml(s) { return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;'); }
  function escapeAttr(s) { return escapeHtml(s).replace(/`/g, '&#96;'); }
  function formatMathText(s) {
    let out = escapeHtml(s || '');
    out = out.replace(/q0/g, 'q<sub>0</sub>');
    out = out.replace(/A0/g, 'A<sub>0</sub>').replace(/G0/g, 'G<sub>0</sub>').replace(/L0/g, 'L<sub>0</sub>');
    out = out.replace(/([A-Za-z])\^(\d+)/g, '$1<sup>$2</sup>');
    out = out.replace(/Σ\*/g, 'Σ<sup>*</sup>').replace(/T\*/g, 'T<sup>*</sup>').replace(/N\*/g, 'N<sup>*</sup>');
    return out;
  }
});
